{"content":"1: use clippy_utils::diagnostics::span_lint_hir_and_then;
2: use clippy_utils::source::snippet;
3: use hir::def::{DefKind, Res};
4: use rustc_data_structures::fx::FxHashSet;
5: use rustc_errors::Applicability;
6: use rustc_hir::attrs::AttributeKind;
7: use rustc_hir::{self as hir, AmbigArg, find_attr};
8: use rustc_lint::{LateContext, LateLintPass, LintContext};
9: use rustc_session::impl_lint_pass;
10: use rustc_span::Span;
11: use rustc_span::edition::Edition;
12: use std::collections::BTreeMap;
13: 
14: declare_clippy_lint! {
15:     /// ### What it does
16:     /// Checks for `#[macro_use] use...`.
17:     ///
18:     /// ### Why is this bad?
19:     /// Since the Rust 2018 edition you can import
20:     /// macro's directly, this is considered idiomatic.
21:     ///
22:     /// ### Example
23:     /// ```rust,ignore
24:     /// #[macro_use]
25:     /// extern crate some_crate;
26:     ///
27:     /// fn main() {
28:     ///     some_macro!();
29:     /// }
30:     /// ```
31:     ///
32:     /// Use instead:
33:     ///
34:     /// ```rust,ignore
35:     /// use some_crate::some_macro;
36:     ///
37:     /// fn main() {
38:     ///     some_macro!();
39:     /// }
40:     /// ```
41:     #[clippy::version = "1.44.0"]
42:     pub MACRO_USE_IMPORTS,
43:     pedantic,
44:     "#[macro_use] is no longer needed"
45: }
46: 
47: /// `MacroRefData` includes the name of the macro.
48: #[derive(Debug, Clone)]
49: pub struct MacroRefData {
50:     name: String,
51: }
52: 
53: impl MacroRefData {
54:     pub fn new(name: String) -> Self {
55:         Self { name }
56:     }
57: }
58: 
59: #[derive(Default)]
60: pub struct MacroUseImports {
61:     /// the actual import path used and the span of the attribute above it. The value is
62:     /// the location, where the lint should be emitted.
63:     imports: Vec<(String, Span, hir::HirId)>,
64:     /// the span of the macro reference, kept to ensure only one reference is used per macro call.
65:     collected: FxHashSet<Span>,
66:     mac_refs: Vec<MacroRefData>,
67: }
68: 
69: impl_lint_pass!(MacroUseImports => [MACRO_USE_IMPORTS]);
70: 
71: impl MacroUseImports {
72:     fn push_unique_macro(&mut self, cx: &LateContext<'_>, span: Span) {
73:         let call_site = span.source_callsite();
74:         let name = snippet(cx, cx.sess().source_map().span_until_char(call_site, '!'), "_");
75:         if span.source_callee().is_some() && !self.collected.contains(&call_site) {
76:             let name = if name.contains("::") {
77:                 name.split("::").last().unwrap().to_string()
78:             } else {
79:                 name.to_string()
80:             };
81: 
82:             self.mac_refs.push(MacroRefData::new(name));
83:             self.collected.insert(call_site);
84:         }
85:     }
86: 
87:     fn push_unique_macro_pat_ty(&mut self, cx: &LateContext<'_>, span: Span) {
88:         let call_site = span.source_callsite();
89:         let name = snippet(cx, cx.sess().source_map().span_until_char(call_site, '!'), "_");
90:         if span.source_callee().is_some() && !self.collected.contains(&call_site) {
91:             self.mac_refs.push(MacroRefData::new(name.to_string()));
92:             self.collected.insert(call_site);
93:         }
94:     }
95: }
