97: impl LateLintPass<'_> for MacroUseImports {
98:     fn check_item(&mut self, cx: &LateContext<'_>, item: &hir::Item<'_>) {
99:         if cx.sess().opts.edition >= Edition::Edition2018
100:             && let hir::ItemKind::Use(path, _kind) = &item.kind
101:             && let hir_id = item.hir_id()
102:             && let attrs = cx.tcx.hir_attrs(hir_id)
103:             && let Some(mac_attr_span) = find_attr!(attrs, AttributeKind::MacroUse {span, ..} => *span)
104:             && let Some(Res::Def(DefKind::Mod, id)) = path.res.type_ns
105:             && !id.is_local()
106:         {
107:             for kid in cx.tcx.module_children(id) {
108:                 if let Res::Def(DefKind::Macro(_mac_type), mac_id) = kid.res {
109:                     let def_path = cx.tcx.def_path_str(mac_id);
110:                     self.imports.push((def_path, mac_attr_span, hir_id));
111:                 }
112:             }
113:         } else if item.span.from_expansion() {
114:             self.push_unique_macro_pat_ty(cx, item.span);
115:         }
116:     }
117:     fn check_expr(&mut self, cx: &LateContext<'_>, expr: &hir::Expr<'_>) {
118:         if expr.span.from_expansion() {
119:             self.push_unique_macro(cx, expr.span);
120:         }
121:     }
122:     fn check_stmt(&mut self, cx: &LateContext<'_>, stmt: &hir::Stmt<'_>) {
123:         if stmt.span.from_expansion() {
124:             self.push_unique_macro(cx, stmt.span);
125:         }
126:     }
127:     fn check_pat(&mut self, cx: &LateContext<'_>, pat: &hir::Pat<'_>) {
128:         if pat.span.from_expansion() {
129:             self.push_unique_macro_pat_ty(cx, pat.span);
130:         }
131:     }
132:     fn check_ty(&mut self, cx: &LateContext<'_>, ty: &hir::Ty<'_, AmbigArg>) {
133:         if ty.span.from_expansion() {
134:             self.push_unique_macro_pat_ty(cx, ty.span);
135:         }
136:     }
137:     fn check_crate_post(&mut self, cx: &LateContext<'_>) {
138:         let mut used = BTreeMap::new();
139:         let mut check_dup = vec![];
140:         for (import, span, hir_id) in &self.imports {
141:             let found_idx = self.mac_refs.iter().position(|mac| import.ends_with(&mac.name));
142: 
143:             if let Some(idx) = found_idx {
144:                 self.mac_refs.remove(idx);
145:                 let seg = import.split("::").collect::<Vec<_>>();
146: 
147:                 match seg.as_slice() {
148:                     // an empty path is impossible
149:                     // a path should always consist of 2 or more segments
150:                     [] | [_] => return,
151:                     [root, item] => {
152:                         if !check_dup.contains(&(*item).to_string()) {
153:                             used.entry((
154:                                 (*root).to_string(),
155:                                 span,
156:                                 hir_id.local_id,
157:                                 cx.tcx.def_path_hash(hir_id.owner.def_id.into()),
158:                             ))
159:                             .or_insert_with(|| (vec![], hir_id))
160:                             .0
161:                             .push((*item).to_string());
162:                             check_dup.push((*item).to_string());
163:                         }
164:                     },
165:                     [root, rest @ ..] => {
166:                         if rest.iter().all(|item| !check_dup.contains(&(*item).to_string())) {
167:                             let filtered = rest
168:                                 .iter()
169:                                 .filter_map(|item| {
170:                                     if check_dup.contains(&(*item).to_string()) {
171:                                         None
172:                                     } else {
173:                                         Some((*item).to_string())
174:                                     }
175:                                 })
176:                                 .collect::<Vec<_>>();
177:                             used.entry((
178:                                 (*root).to_string(),
179:                                 span,
180:                                 hir_id.local_id,
181:                                 cx.tcx.def_path_hash(hir_id.owner.def_id.into()),
182:                             ))
183:                             .or_insert_with(|| (vec![], hir_id))
184:                             .0
185:                             .push(filtered.join("::"));
186:                             check_dup.extend(filtered);
187:                         } else {
188:                             let rest = rest.to_vec();
189:                             used.entry((
190:                                 (*root).to_string(),
191:                                 span,
192:                                 hir_id.local_id,
193:                                 cx.tcx.def_path_hash(hir_id.owner.def_id.into()),
194:                             ))
195:                             .or_insert_with(|| (vec![], hir_id))
196:                             .0
197:                             .push(rest.join("::"));
198:                             check_dup.extend(rest.iter().map(ToString::to_string));
199:                         }
200:                     },
201:                 }
202:             }
203:         }
204: 
205:         // If mac_refs is not empty we have encountered an import we could not handle
206:         // such as `std::prelude::v1::foo` or some other macro that expands to an import.
207:         if self.mac_refs.is_empty() {
208:             for ((root, span, ..), (path, hir_id)) in used {
209:                 let import = if let [single] = &path[..] {
210:                     format!("{root}::{single}")
211:                 } else {
212:                     format!("{root}::{{{}}}", path.join(", "))
213:                 };
214: 
215:                 span_lint_hir_and_then(
216:                     cx,
217:                     MACRO_USE_IMPORTS,
218:                     *hir_id,
219:                     *span,
220:                     "`macro_use` attributes are no longer needed in the Rust 2018 edition",
221:                     |diag| {
222:                         diag.span_suggestion(
223:                             *span,
224:                             "remove the attribute and import the macro directly, try",
225:                             format!("use {import};"),
226:                             Applicability::MaybeIncorrect,
227:                         );
228:                     },
229:                 );
230:             }
231:         }
232:     }
233: }
